import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, tap, catchError, throwError, of } from 'rxjs';
import { map } from 'rxjs/operators';
import { API_BASE } from './api.service';
import { ApiResponse } from '../models/common.models';
import { LoginRequest, LoginResponse, SetupPasswordRequest, CurrentUser } from '../models/auth.models';

// Only the access token and user profile live in localStorage. The refresh token is
// kept in an HttpOnly cookie set by the backend — unreadable by JS, immune to XSS.
const ACCESS_KEY = 'uclms_access';
const USER_KEY   = 'uclms_user';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private _user = signal<CurrentUser | null>(this.loadUser());
  readonly currentUser = this._user.asReadonly();
  readonly isLoggedIn = computed(() => this._user() !== null);
  readonly role = computed(() => this._user()?.role ?? '');

  constructor(private http: HttpClient, private router: Router) {}

  login(req: LoginRequest): Observable<LoginResponse> {
    return this.http.post<ApiResponse<LoginResponse>>(
      `${API_BASE}/auth/login`, req, { withCredentials: true }
    ).pipe(
      map(r => r.data),
      tap(data => this.storeSession(data))
    );
  }

  setupPassword(req: SetupPasswordRequest): Observable<void> {
    return this.http.post<ApiResponse<void>>(`${API_BASE}/auth/setup-password`, req).pipe(map(() => void 0));
  }

  /** Silently exchanges the HttpOnly refresh cookie for a fresh access token. */
  refresh(): Observable<LoginResponse> {
    return this.http.post<ApiResponse<LoginResponse>>(
      `${API_BASE}/auth/refresh`, {}, { withCredentials: true }
    ).pipe(
      map(r => r.data),
      tap(data => this.storeSession(data)),
      catchError(err => { this.clearClientSession(); return throwError(() => err); })
    );
  }

  logout(): void {
    // Best-effort: ask the backend to revoke the refresh token and clear the cookie.
    // We don't wait for it — the user is signed out client-side immediately either way.
    this.http.post(`${API_BASE}/auth/revoke`, {}, { withCredentials: true })
      .pipe(catchError(() => of(null)))
      .subscribe(() => this.completeLogout());
    // Clear local state immediately so the UI doesn't flash protected content.
    this.completeLogout();
  }

  getAccessToken(): string | null { return localStorage.getItem(ACCESS_KEY); }

  hasRole(...roles: string[]): boolean {
    const r = this.role();
    return roles.some(role => role === r);
  }

  private storeSession(data: LoginResponse): void {
    localStorage.setItem(ACCESS_KEY, data.accessToken);
    const user: CurrentUser = { userId: data.userId, fullName: data.fullName, email: data.email, role: data.role };
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._user.set(user);
  }

  private clearClientSession(): void {
    localStorage.removeItem(ACCESS_KEY);
    localStorage.removeItem(USER_KEY);
    this._user.set(null);
  }

  private completeLogout(): void {
    this.clearClientSession();
    this.router.navigate(['/auth/login']);
  }

  private loadUser(): CurrentUser | null {
    try { return JSON.parse(localStorage.getItem(USER_KEY) ?? 'null'); } catch { return null; }
  }
}
